import{_ as n,o as a,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"30. Superannuation","description":"","frontmatter":{"title":"30. Superannuation","eba":"Allied Health Professionals 2021-2026","topics":["wages","superannuation","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/wages/30-superannuation.md","filePath":"ebas/allied-health/wages/30-superannuation.md"}'),r={name:"ebas/allied-health/wages/30-superannuation.md"};function i(s,e,p,u,l,d){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_30-superannuation" tabindex="-1">30. Superannuation <a class="header-anchor" href="#_30-superannuation" aria-label="Permalink to &quot;30. Superannuation&quot;">​</a></h1><p>The subject of superannuation is dealt with extensively by federal legislation which prescribes the obligations and entitlements regarding superannuation. This clause 30 is ancillary to and supplements those provisions.</p><p><strong>30.1</strong> Definitions In this clause 30:</p><p><strong>(a)</strong> Default Fund means the Aware Super (or any successor) while it provides a “MySuper product” as defined by the Act.</p><p><strong>(b)</strong> Preferred Superannuation Fund means a fund that meets the definition of a superannuation fund in the Superannuation Guarantee (Administration) Act 1992 (Cth).</p><p><strong>(c)</strong> Industry Superannuation Fund means a complying superannuation fund, as defined in the Superannuation Industry (Supervision) Act 1993, that:</p><p><strong>(i)</strong> has twenty or more participating employers;</p><p><strong>(ii)</strong> excluding any independent directors, provides for half of the trustee board to be comprised of employee representatives and/or nominated by one or more trade unions and half of the trustee board to be comprised of representatives of participating employers; and</p><p><strong>(iii)</strong> operates on a “not for profit” basis.</p><p><strong>30.2</strong> Superannuation contributions The Employer will make superannuation contributions on behalf of an Employee to any of the following superannuation funds nominated by an Employee:</p><p><strong>(a)</strong> HESTA (Health Employees Superannuation Trust of Australia) or successor;</p><p><strong>(b)</strong> Aware Super (Aware Super Pty Ltd), or successor;</p><p><strong>(c)</strong> the Employee’s preferred superannuation fund where it is an Industry Superannuation Fund; or</p><p><strong>(d)</strong> where relevant superannuation legislation requires choice of superannuation fund in an enterprise agreement, any other Preferred Superannuation Fund nominated by the Employee.</p><p><strong>30.3</strong> New Employee does not nominate fund If the Employee does not nominate a fund, the Employer will pay the Employee&#39;s superannuation contributions to the Default Fund, or where required by superannuation legislation to the Employee’s stapled superannuation fund.</p><p><strong>30.4</strong> Calculation of superannuation contributions</p><p><strong>(a)</strong> Superannuation contributions paid by the Employer will be calculated and paid on:</p><p><strong>(i)</strong> ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth), calculated on the Employee’s pre salary packaging earnings;</p><p><strong>(ii)</strong> any additional amounts consistent with the trust deed of the superannuation fund; and</p><p><strong>(iii)</strong> a period of paid parental leave until 6 July 2022 in accordance with subclause 30.5(b) of the 2020 Agreement, after which superannuation shall be paid on parental leave (paid and unpaid) in accordance with subclause 30.6.</p><p><strong>30.5</strong> Employee Contributions Subject to the terms of the relevant trust deed of the superannuation fund, an Employee may make additional contributions to their chosen superannuation</p><p>fund and upon receiving written authorisation from the Employee, the Employer will deduct such contributions from an Employee&#39;s salary and will forward such contributions to the chosen fund.</p><p><strong>30.6</strong> Superannuation during parental leave – from 7 July 2022 From 7 July 2022, the Employer will make superannuation contributions throughout any period of parental leave, paid or unpaid. Such contributions will be calculated as follows:</p><p><strong>(a)</strong> the Employee&#39;s ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth) calculated on the Employee&#39;s pre- salary packaging earnings and any additional amounts consistent with the trust deed of the superannuation fund over 26 full pay periods (that is over 52 weeks) immediately prior to commencing parental leave and divided by 52 (Weekly Parental Leave Super Contribution);</p><p><strong>(b)</strong> the Weekly Parental Leave Super Contribution will be paid during each week of Parental Leave (both paid and unpaid) save that:</p><p><strong>(i)</strong> the Employee will receive a pro rata payment for a period less than one (1) week; and</p><p><strong>(ii)</strong> where, during the period of parental leave (either paid or unpaid), the Employee&#39;s rate of pay increases under subclause 28.1, the Employee&#39;s pre-salary packaging earnings as calculated above will be increased accordingly from the relevant date and superannuation paid on the increased amount.</p><p>Plain language terms: super, SG.</p>',28)])])}const g=n(r,[["render",i]]);export{c as __pageData,g as default};
